INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Side-Lying_Floor_Stretch','Side-Lying Floor Stretch','dorsales',ARRAY[]::text[],NULL,'stretching',ARRAY['First lie on your left side, bending your left knee in front of you to stabilize your torso (use your abdominal muscles as well to hold you upright).','Straighten your right leg and rest the right foot on the floor behind your left. Straighten your right arm over your head and gently pull on your right wrist to stretch the entire right side of the body. Switch sides.'],'First lie on your left side, bending your left knee in front of you to stabilize your torso (use your abdominal muscles as well to hold you upright). Straighten your right leg and rest the right foot on the floor behind your left. Straighten your right arm over your head and gently pull on your right wrist to stretch the entire right side of the body. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side-Lying_Floor_Stretch/0.jpg','exercisedb',true),('Side_Bridge','Side Bridge','abdominales',ARRAY['hombros'],'peso corporal','strength',ARRAY[]::text[],NULL,'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Bridge/0.jpg','exercisedb',true),('Side_Hop-Sprint','Side Hop-Sprint','cuádriceps',ARRAY['abductores','aductores','pantorrillas','isquiotibiales'],'otro','plyometrics',ARRAY['Stand to the side of a cone or hurdle.','Begin this drill by hopping sideways over the obstacle, rebounding out of your landing to hop back to where you started.','Hop for a prescribed number or repetitions as quickly as possible, and finish this drill by sprinting a short distance upon landing the last hop.'],'Stand to the side of a cone or hurdle. Begin this drill by hopping sideways over the obstacle, rebounding out of your landing to hop back to where you started. Hop for a prescribed number or repetitions as quickly as possible, and finish this drill by sprinting a short distance upon landing the last hop.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Hop-Sprint/0.jpg','exercisedb',true),('Side_Jackknife','Side Jackknife','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY[]::text[],NULL,'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Jackknife/0.jpg','exercisedb',true),('Side_Lateral_Raise','Side Lateral Raise','hombros',ARRAY[]::text[],'mancuernas','strength',ARRAY['Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.','While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbells back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position. While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top. Lower the dumbbells back down slowly to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Lateral_Raise/0.jpg','exercisedb',true),('Side_Laterals_to_Front_Raise','Side Laterals to Front Raise','hombros',ARRAY['trapecios'],'mancuernas','strength',ARRAY['In a standing position, hold a pair of dumbbells at your side. This will be your starting position.','Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.','At the top of the exercise move the weights out in front of you, keeping your arms extended.','Lower the weights with a controlled motion.','On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides.','Lower the weights to the starting position.'],'In a standing position, hold a pair of dumbbells at your side. This will be your starting position. Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating. At the top of the exercise move the weights out in front of you, keeping your arms extended. Lower the weights with a controlled motion. On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides. Lower the weights to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Laterals_to_Front_Raise/0.jpg','exercisedb',true),('Side_Leg_Raises','Side Leg Raises','aductores',ARRAY[]::text[],'peso corporal','stretching',ARRAY['Stand next to a chair, which you may hold onto as a support. Stand on one leg. This will be your starting position.','Keeping your leg straight, raise it as far out to the side as possible, and swing it back down, allowing it to cross the opposite leg.','Repeat this swinging motion 5-10 times, increasing the range of motion as you do so.'],'Stand next to a chair, which you may hold onto as a support. Stand on one leg. This will be your starting position. Keeping your leg straight, raise it as far out to the side as possible, and swing it back down, allowing it to cross the opposite leg. Repeat this swinging motion 5-10 times, increasing the range of motion as you do so.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Leg_Raises/0.jpg','exercisedb',true),('Side_Lying_Groin_Stretch','Side Lying Groin Stretch','aductores',ARRAY['isquiotibiales'],NULL,'stretching',ARRAY['Start off by lying on your right side and bend your right knee in front of you to stabilize the torso.','Rest your head on your right hand or shoulder. Lift your left leg upward and hold it by the back of the knee (easier) or the foot (harder).','Pull your left knee in toward your left shoulder and simultaneously press your foot or knee down to the floor. To intensify this stretch, straighten your left leg. Switch sides.'],'Start off by lying on your right side and bend your right knee in front of you to stabilize the torso. Rest your head on your right hand or shoulder. Lift your left leg upward and hold it by the back of the knee (easier) or the foot (harder). Pull your left knee in toward your left shoulder and simultaneously press your foot or knee down to the floor. To intensify this stretch, straighten your left leg. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Lying_Groin_Stretch/0.jpg','exercisedb',true),('Side_Neck_Stretch','Side Neck Stretch','cuello',ARRAY[]::text[],NULL,'stretching',ARRAY['Start with your shoulders relaxed, gently tilt your head towards your shoulder.','Assist stretch with a gentle pull on the side of the head.'],'Start with your shoulders relaxed, gently tilt your head towards your shoulder. Assist stretch with a gentle pull on the side of the head.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Neck_Stretch/0.jpg','exercisedb',true),('Side_Standing_Long_Jump','Side Standing Long Jump','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],NULL,'plyometrics',ARRAY['Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position.','Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can.','Land facing the same direction with your feet hip width apart, absorbing the impact through your lower body.'],'Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position. Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can. Land facing the same direction with your feet hip width apart, absorbing the impact through your lower body.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Standing_Long_Jump/0.jpg','exercisedb',true);